Bash(NODE_PATH=/tmp/node_modules node -e "
const Jimp = require\('jimp'\);
Jimp.read\('C:/Users/matte/Downloads/cat_temp.png'\).then\(img => {
  const W = img.getWidth\(\), H = img.getHeight\(\);

  // Sample some pixels to understand zones
  // Background is top-left area - cream/beige ~f4e8cc range
  // Let's look at specific areas
  const zones = {
    'top-left \(bg\)': [5,5],
    'top-right \(bg\)': [115,5],
    'center \(cat body\)': [70,60],
    'outline area': [55,20],
    'belly area': [55,75],
    'bottom-left \(floor\)': [10,125],
    'bottom-right \(carpet\)': [80,120],
    'cat head': [65,35],
    'ear area': [55,15],
    'tail': [85,105],
  };

  for \(const [name, [x,y]] of Object.entries\(zones\)\) {
    const c = img.getPixelColor\(x, y\);
    const r = \(c >> 24\) & 0xFF, g = \(c >> 16\) & 0xFF, b = \(c >> 8\) & 0xFF;
    console.log\(name, x, y, '#' + [r,g,b].map\(v => v.toString\(16\).padStart\(2,'0'\)\).join\(''\)\);
  }

  // Now let's do color clustering - group into buckets
  // Define target color ranges
  const pixels = [];
  for \(let y = 0; y < H; y++\) {
    for \(let x = 0; x < W; x++\) {
      const c = img.getPixelColor\(x, y\);
      const r = \(c >> 24\) & 0xFF, g = \(c >> 16\) & 0xFF, b = \(c >> 8\) & 0xFF;
      pixels.push\({x, y, r, g, b}\);
    }
  }

  // Classify by luminance and hue
  function classify\(r, g, b\) {
    const lum = 0.299*r + 0.587*g + 0.114*b;
    const max = Math.max\(r,g,b\), min = Math.min\(r,g,b\);
    const sat = max === 0 ? 0 : \(max-min\)/max;

    // Very dark = outline
    if \(lum < 40\) return 'outline';
    // Dark browns \(fur shadow\)
    if \(lum < 80 && sat > 0.15\) return 'fur_dark';
    // Dark grays/muted
    if \(lum < 80\) return 'outline_soft';
    // Medium saturated oranges/browns = main fur
    if \(lum >= 80 && lum < 170 && r > g && sat > 0.2\) return 'fur';
    // Light saturated = fur light
    if \(lum >= 170 && lum < 220 && sat > 0.1 && r > g\) return 'fur_light';
    // Very light cream/white with some warmth = belly/highlight
    if \(lum >= 220 && sat < 0.15\) return 'belly';
    // Light background
    if \(lum >= 200 && sat < 0.2\) return 'background';
    // Green-ish = carpet
    if \(g > r && g > b\) return 'carpet';
    // Floor brown
    if \(lum >= 80 && lum < 170 && sat < 0.3\) return 'floor';
    return 'other';
  }

  const counts = {};
  pixels.forEach\(p => {
    const cls = classify\(p.r, p.g, p.b\);
    counts[cls] = \(counts[cls] || 0\) + 1;
  }\);
  console.log\('\\\\nClassification:', JSON.stringify\(counts, null, 2\)\);
}\).catch\(e => console.error\(e\)\);
" 2>&1)
